const genocideCases = [
  { title: 'The Srebrenica Massacre', category: 'genocide', summary: 'In July 1995, Bosnian Serb forces under General Ratko Mladic systematically executed over 8,000 Bosniak Muslim men and boys near Srebrenica — Europe\'s worst atrocity since the Holocaust.', location: 'Srebrenica, Bosnia and Herzegovina', date: 'July 1995', featured: true, fullContent: 'The Srebrenica massacre occurred between July 11–22, 1995, when Bosnian Serb forces under General Ratko Mladic captured the UN-declared "safe area" of Srebrenica and executed over 8,000 Bosniak Muslim men and boys. Dutch UN peacekeepers (Dutchbaat) were present but unable to prevent the killings. Women and girls were expelled; men and boys were separated and bussed to execution sites across the region, shot in forests, fields, and warehouses. Bodies were initially buried in mass graves, then exhumed and reburied in secondary graves to hide evidence. DNA identification work by the International Commission on Missing Persons (ICMP) has identified over 7,000 victims. The ICTY convicted Mladic of genocide in 2017 and sentenced him to life imprisonment.', timeline: JSON.stringify([{ year: '1993', event: 'UN declares Srebrenica a "safe area"' }, { year: '1995 Jul 11', event: 'Mladic\'s forces capture Srebrenica; Dutch peacekeepers cannot stop them' }, { year: '1995 Jul 11–22', event: 'Over 8,000 men and boys systematically executed' }, { year: '1995', event: 'Bodies initially buried; then exhumed and reburied to destroy evidence' }, { year: '2004', event: 'International Court of Justice rules it genocide' }, { year: '2017', event: 'Mladic convicted of genocide; sentenced to life' }]), keyFacts: JSON.stringify(['8,000+ men and boys executed in 11 days', 'Europe\'s worst atrocity since WWII', 'Dutch UN peacekeepers present but unable to intervene', 'Bodies reburied in secondary graves to destroy evidence', 'DNA identification still ongoing 30 years later', 'Mladic convicted of genocide 2017; sentenced to life']), perpetrator: 'General Ratko Mladic and Bosnian Serb Army (VRS). Mladic convicted of genocide 2017.', victims: '8,000+ Bosniak Muslim men and boys aged 13–77.', verdict: 'ICTY: Mladic convicted genocide, crimes against humanity (2017) — life. Radovan Karadžić also convicted — life.', links: JSON.stringify([{ label: 'Wikipedia — Srebrenica Massacre', url: 'https://en.wikipedia.org/wiki/Srebrenica_massacre', type: 'article' }, { label: 'Srebrenica Memorial Centre', url: 'https://srebrenica.org.ba/', type: 'official' }, { label: 'ICTY Mladic Judgment', url: 'https://www.icty.org/case/mladic', type: 'official' }]) },
  { title: 'The Nanking Massacre (Rape of Nanking)', category: 'genocide', summary: 'Between December 1937 and January 1938, Imperial Japanese troops killed an estimated 200,000–300,000 Chinese civilians and POWs in six weeks of systematic atrocity in Nanjing.', location: 'Nanjing (Nanking), China', date: 'December 1937 – January 1938', featured: true, fullContent: 'The Nanking Massacre (also called the Rape of Nanking) occurred after Japanese forces captured the Chinese city of Nanjing on December 13, 1937. Over the following six weeks, Japanese soldiers engaged in mass murder, looting, and rape on an enormous scale. Conservative estimates put the death toll at 200,000; Chinese sources cite up to 300,000. POWs and civilians were used for bayonet practice, buried alive, doused in gasoline and burned, and subjected to competitive killing contests between Japanese officers reported in Japanese newspapers. An estimated 20,000–80,000 women were raped. A small "Safety Zone" established by Western residents including Nazi Party member John Rabe saved approximately 200,000–250,000 lives. Japan has never formally apologized and the massacre remains a source of deep tension between China and Japan.', timeline: JSON.stringify([{ year: '1937 Dec 13', event: 'Japanese forces capture Nanjing' }, { year: '1937 Dec 13 – 1938 Jan', event: 'Six weeks of mass murder, rape, and looting' }, { year: '1938', event: 'International Safety Zone refugees begin returning to city' }, { year: '1946–1948', event: 'International Military Tribunal for the Far East (Tokyo Trials)' }, { year: '1997', event: 'Iris Chang publishes The Rape of Nanking; international attention renewed' }]), keyFacts: JSON.stringify(['200,000–300,000 killed in 6 weeks', '20,000–80,000 women raped', 'Competitive killing contests reported in Japanese press', 'Safety Zone protected ~250,000 civilians', 'Nazi Party member John Rabe organized the Safety Zone', 'Japan never formally apologized; major diplomatic tension continues']), perpetrator: 'Imperial Japanese Army under General Matsui Iwane and Prince Asaka Yasuhiko.', victims: '200,000–300,000 Chinese civilians and POWs.', verdict: 'Tokyo Trials (1946): General Matsui Iwane executed. Prince Asaka not prosecuted due to imperial immunity. Japan never gave full formal apology.', links: JSON.stringify([{ label: 'Wikipedia — Nanjing Massacre', url: 'https://en.wikipedia.org/wiki/Nanjing_massacre', type: 'article' }, { label: 'Book: The Rape of Nanking by Iris Chang', url: 'https://www.goodreads.com/book/show/95800', type: 'book' }, { label: 'Nanjing Massacre Memorial Hall', url: 'https://www.nj1937.org/', type: 'official' }]) },
  { title: 'The Khmer Rouge Killing Fields', category: 'genocide', summary: 'The execution sites of the Khmer Rouge regime in Cambodia, where an estimated 1.3 million people were taken and killed between 1975 and 1979.', location: 'Choeung Ek and across Cambodia', date: '1975–1979', featured: false, fullContent: 'The Killing Fields is the term given to the execution sites used by the Khmer Rouge regime during the Cambodian genocide. The most famous site is Choeung Ek, 15 km south of Phnom Penh, where 17,000 people were transported from the S-21 Tuol Sleng prison and executed. Techniques included bludgeoning with hammers, shovels, and bamboo to save bullets. Children were killed by swinging them against a "Killing Tree" — the tree still stands at the memorial. The ground at Choeung Ek still yields bone fragments after rain. A large memorial stupa contains 8,000 skulls. The 1984 film The Killing Fields, based on journalist Sydney Schanberg\'s account of his photographer Dith Pran\'s survival, brought the story to international attention.', timeline: JSON.stringify([{ year: '1975', event: 'Khmer Rouge captures Phnom Penh; S-21 prison begins operations' }, { year: '1975–1979', event: 'Choeung Ek and 300+ other killing sites operational nationwide' }, { year: '1979', event: 'Vietnamese invasion ends the Khmer Rouge regime' }, { year: '1980', event: 'Choeung Ek discovered; mass graves exhumed' }, { year: '1984', event: 'Film "The Killing Fields" brings international attention' }]), keyFacts: JSON.stringify(['17,000 taken from S-21 prison to Choeung Ek alone', 'Bullets rarely used — hammers, bamboo, machetes instead', 'Children killed by being swung against trees', 'Killing Tree still stands as memorial', 'Ground still yields bone fragments after heavy rain', '300+ Killing Fields sites across Cambodia']), perpetrator: 'Khmer Rouge under Pol Pot. Key executioners at S-21: Kaing Guek Eav (Comrade Duch), convicted 2010.', victims: 'Approximately 1.3 million at Killing Fields sites. Total genocide: 1.5–2 million.', verdict: 'ECCC: Duch convicted 2010 (life). Nuon Chea and Khieu Samphan convicted genocide 2018 (life).', links: JSON.stringify([{ label: 'Wikipedia — Killing Fields', url: 'https://en.wikipedia.org/wiki/Killing_fields', type: 'article' }, { label: 'Film: The Killing Fields (1984)', url: 'https://www.imdb.com/title/tt0087553/', type: 'documentary' }, { label: 'Choeung Ek Memorial', url: 'https://www.killingfieldsmuseum.com/', type: 'official' }]) },
  { title: 'The Bosnian War Ethnic Cleansing', category: 'genocide', summary: 'Systematic campaign of ethnic cleansing, mass murder, and rape by Bosnian Serb forces during the 1992–1995 Bosnian War — the worst European atrocity since WWII.', location: 'Bosnia and Herzegovina', date: '1992–1995', featured: false, fullContent: 'The Bosnian War (1992–1995) saw the systematic ethnic cleansing of Bosniak Muslims and Croats by Bosnian Serb forces (VRS) under Radovan Karadžić and Ratko Mladic. "Ethnic cleansing" involved murder, mass rape, concentration camps, and the forced deportation of entire communities. The siege of Sarajevo — the longest siege of a capital city in modern warfare history (1,425 days) — saw Serb forces shell and snipe civilians daily. Detention camps like Omarska, Keraterm, and Manjača held thousands of Muslim and Croat men in horrific conditions; murder and torture were routine. An estimated 100,000 people were killed; 2.2 million displaced. The Srebrenica massacre was the pinnacle atrocity. The ICTY prosecuted 161 individuals.', timeline: JSON.stringify([{ year: '1992 Apr', event: 'Bosnian War begins; Sarajevo siege begins (lasts 1,425 days)' }, { year: '1992', event: 'Concentration camps established — Omarska, Keraterm, Manjača' }, { year: '1992–1995', event: 'Systematic ethnic cleansing of Muslims and Croats across Bosnia' }, { year: '1995 Jul', event: 'Srebrenica massacre — 8,000+ killed' }, { year: '1995 Nov', event: 'Dayton Agreement ends the war' }, { year: '2001–2019', event: 'ICTY prosecutes 161 individuals; Mladic and Karadžić jailed for life' }]), keyFacts: JSON.stringify(['100,000+ killed; 2.2 million displaced', 'Longest siege of capital city in modern warfare (Sarajevo)', 'Systematic mass rape used as weapon of war', 'Concentration camps with torture and murder', 'Srebrenica: 8,000+ executed in 11 days', '161 people prosecuted by ICTY']), perpetrator: 'Bosnian Serb leadership: Radovan Karadžić, Ratko Mladic. Both convicted of genocide and sentenced to life.', victims: 'Approximately 100,000 Bosniak Muslims and Croats.', verdict: 'Karadžić: life (2019). Mladic: life (2017). 161 ICTY convictions total.', links: JSON.stringify([{ label: 'Wikipedia — Bosnian War', url: 'https://en.wikipedia.org/wiki/Bosnian_War', type: 'article' }, { label: 'ICTY — Tribunal Archive', url: 'https://www.icty.org/', type: 'official' }]) },
];
